class Solution {
public:
    vector<int> popcountDepth(vector<long long>& nums, vector<vector<long long>>& queries) {
        int n = nums.size();
        vector<int> answer;
        vector<vector<int>> bit_count(n, vector<int>(16));
        for (int i = 0; i < n; i++) {
            for (int j = 0; j < 16; j++) {
                bit_count[i][j] = popcount(nums[i] & ((1LL << j) - 1));
            }
        }
        for (auto& query : queries) {
            if (query.size() == 4) {
                int l = query[1], r = query[2], k = query[3];
                int left = l, right = r;
                while (left <= right) {
                    int mid = left + (right - left) / 2;
                    int count = 0;
                    for (int j = 0; j < 16; j++) {
                        if (bit_count[mid][j] == k) count++;
                    }
                    if (count > 0) {
                        int next = mid + 1;
                        while (next < n && bit_count[next][0] == 1) next++;
                        if (next < n) {
                            count = 0;
                            for (int j = 0; j < 16; j++) {
                                if (bit_count[next][j] == k) count++;
                            }
                            if (count > 0) {
                                left = mid + 1;
                            } else {
                                right = mid - 1;
                            }
                        } else {
                            left = mid + 1;
                        }
                    } else {
                        right = mid - 1;
                    }
                }
                answer.push_back(right - left + 1);
            } else {
                int idx = query[1], val = query[2];
                for (int j = 0; j < 16; j++) {
                    bit_count[idx][j] = popcount(val & ((1LL << j) - 1));
                }
            }
        }
        return answer;
    }

    int popcount(long long x) {
        int count = 0;
        while (x) {
            count += x & 1;
            x >>= 1;
        }
        return count;
    }
};
